class Trie:
    def __init__(self):
        self.root = TrieNode()

    def delete_key(self, word):
        def dfs(root, idx):
            if not root:
                return False
            if idx == len(word) - 1:
                root.isEndOfWord = False
                return True
            if idx == len(word) - 1 and not root.children[ord(word[idx]) - ord('a')]:
                root.children[ord(word[idx]) - ord('a')] = None
                return True
            return dfs(root.children[ord(word[idx]) - ord('a')], idx + 1)

        return dfs(self.root, 0)

    def insert(self, word):
        def dfs(root, idx):
            if not root:
                root = TrieNode()
            if idx == len(word) - 1:
                root.isEndOfWord = True
                return root
            root.children[ord(word[idx]) - ord('a')] = dfs(root.children[ord(word[idx]) - ord('a')], idx + 1)
            return root

        self.root = dfs(self.root, 0)


