#include <iostream>
#include <fstream>
#include <vector>
#include <string>

using namespace std;

class TrieNode {
public:
    char char;
    bool endOfWord;
    TrieNode* children[26];

    TrieNode(char c) : char(c), endOfWord(false) {}
};

class Trie {
public:
    TrieNode* root;

    Trie() : root(new TrieNode(' ')) {}

    void insert(const string& word) {
        TrieNode* curr = root;
        for (char c : word)
            curr = curr->children[c - 'a'];
        curr->endOfWord = true;
    }

    void deleteKey(const string& word) {
        function<void(TrieNode*, int)> dfs =
            [&](TrieNode* root, int idx)
            {
                if (!root) return;
                if (idx == word.size() - 1) {
                    root->endOfWord = false;
                    return;
                }
                if (idx == word.size() - 1 && !root->children[word[idx] - 'a'])
                    root->children[word[idx] - 'a'] = nullptr;
                dfs(root->children[word[idx] - 'a'], idx + 1);
            };
        dfs(root, 0);
    }

    void print() const
    {
        cout << ' ';
        cout.flush();
        for (int i = 0; i < 26; ++i)
            if (root->children[i])
                cout << root->children[i]->char;
        cout << '\n';
        cout.flush();
    }
};

int main()
{
    ifstream f("input.txt");
    f.tie(nullptr);
    cin.tie(nullptr);
    auto out = ofstream("output.txt");

    int n;
    f >> n;
    f.ignore();
    vector<string> words;
    for (int i = 0; i < n; ++i) {
        string word;
        getline(f, word);
        words.push_back(word);
    }

    Trie trie;
    for (const string& word : words)
        trie.insert(word);

    auto res = trie.deleteKey(words.back());


    cout.flush();
    out << (res ? "YES" : "NO");
    out.flush();

    return 0;
}
